const players = $input.first().json?.result?.data?.squad?.data?.players;

if (!players?.length) {
  throw new Error('Keine Spieler gefunden');
}

return players.map(p => {
  const id = p.person?.id;
  const lastName = p.person?.last_name;
  const firstName = p.person?.first_name;
  const jerseyNumber = p.person?.jersey_number;
  const slug = p.person?.slug;

  if (!id) return null;

  // ID → S3-Pfad: '492931' → '000/492/931'
  const padded = id.padStart(9, '0');
  const s3path = `${padded.slice(0,3)}/${padded.slice(3,6)}/${padded.slice(6,9)}`;

  // Avatar: Originalname mit Umlaut, URL-encoded (Götze → G%C3%B6tze)
  const avatarName = encodeURIComponent(lastName.split(/[\s-]/)[0]);

  // Video: Normalisierter Name ohne Umlaut (Götze → Gotze, Chaïbi → Chaibi)
  const videoName = lastName
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .split(/[\s-]/)[0];

  const avatarUrl = `https://liveticker-eintracht-de.s3.eu-central-1.amazonaws.com/people/liveticker_avatars/${s3path}/large/${avatarName}.png`;

  const videoUrl = jerseyNumber
    ? `https://liveticker-eintracht-de.s3.eu-central-1.amazonaws.com/people/liveticker_videos/${s3path}/original/Torschuetze_${String(jerseyNumber).padStart(2, '0')}_${videoName}_HD_1.mp4`
    : null;

  return {
    json: {
      id,
      slug,
      first_name: firstName,
      last_name: lastName,
      jersey_number: jerseyNumber,
      position: p.person?.position,
      avatar_url: avatarUrl,
      video_url: videoUrl
    }
  };
}).filter(Boolean);

// Für jeden Spieler: SQL-Upsert generieren
// Matched über last_name + jersey_number (kein external_id von EF-Website)
function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return `'${String(val).replace(/'/g, "''")}'`;
}
function num(val) {
  return (val === null || val === undefined) ? 'NULL' : val;
}

return $input.all().map(item => {
  const p = item.json;
  const query = `
    UPDATE players
    SET
      image_url  = ${esc(p.avatar_url)},
      video_url  = ${esc(p.video_url)},
      updated_at = NOW()
    WHERE
      jersey_number = ${num(p.jersey_number)}
      AND team_id IN (
        SELECT id FROM teams WHERE name ILIKE '%Frankfurt%'
      )
    RETURNING id, display_name, jersey_number, video_url
  `.trim();
  return { json: { query, player: p.last_name } };
});
